use crate::int::types::traits::BigInt;

/// Reconstruct one baked binary fixed-point slot at working scale
/// `w` into the tier's work integer `W`. `slot` is the MS-limb-first
/// `round(value · 2^B)` (`B = SINCOS_TANG_B`); we SLICE the high-order
/// `p` limbs needed for this scale and reconstruct
///
/// ```text
/// round(value · 10^w) = round(slot_hi · 10^w / 2^bp)
///                     = (slot_hi · 10^w + 2^(bp−1)) >> bp
/// ```
///
/// where `bp = 64·p`. The MS-limb-first layout makes the slice a
/// contiguous high-limb PREFIX. `pow10_w` is `10^w` in `W`, supplied
/// by the caller from the kernel's baked `pow10_table` (a lookup, not
/// a per-call recompute).
#[inline]
fn reconstruct<W: BigInt>(slot: &[u64; SINCOS_TANG_LIMBS], w: u32, pow10_w: W) -> W {
    // Binary precision needed: w·log2(10) value bits + guard. Use the
    // rational 3322/1000 ≈ log2(10) (a slight over-estimate) and a
    // 64-bit (one-limb) guard so the converted slot rounds correctly
    // yet the conversion product `slot_hi · 10^w` stays inside `W`
    // even on the narrowest work integer (same budget as the `ln`
    // pilot). Round the limb count up; clamp to the stored width.
    let need_bits = (w as u64) * 3322 / 1000 + 64;
    let mut p = ((need_bits + 63) / 64) as usize;
    if p < 1 {
        p = 1;
    }
    if p > SINCOS_TANG_LIMBS {
        p = SINCOS_TANG_LIMBS;
    }
    // Zero-extend the top `p` limbs (MS-first) into W:
    //   slot_hi = sum_{k=0..p-1} slot[k] · 2^(64·(p−1−k)).
    let mut slot_hi = W::ZERO;
    for k in 0..p {
        slot_hi = (slot_hi << 64)
            | W::from_mag_sign_u128(&[slot[k] as u128], false);
    }
    let bp = (64 * p) as u32;
    let scaled = slot_hi * pow10_w;
    // Round-half-up: add 2^(bp−1), then shift right by bp.
    let bias = W::ONE << (bp - 1);
    (scaled + bias) >> bp
}

/// `(sin(c_j), cos(c_j))` with `c_j = idx·π/(4·m)` reconstructed at
/// working scale `w` (`idx ∈ [0, m]`, `m = SINCOS_TANG_M`) in the
/// tier's work integer `W` (a value `x` held as `x · 10^w`). Replaces
/// the per-call `sin_cos_fixed` Series recompute.
///
/// `idx = 0` short-circuits to `(0, pow10_w)` = `(sin 0, cos 0)`
/// at scale `w`; this is the only pair with an integer digit (`cos 0
/// = 1`), so it is NOT stored as a B-bit fraction. For `idx ≥ 1` both
/// `sin(c_j)` and `cos(c_j)` are pure fractions `< 1` read from the
/// baked tables. `m` MUST equal `SINCOS_TANG_M` (debug-asserted).
///
/// `pow10_w` is `10^w` in `W`, supplied by the caller from the
/// kernel's baked `pow10_table` (a lookup, not a `W::TEN.pow(w)`
/// per-call recompute).
#[inline]
pub(crate) fn sincos_table_entry_baked<W: BigInt>(
    w: u32,
    idx: usize,
    m: u32,
    pow10_w: W,
) -> (W, W) {
    debug_assert!(
        m == SINCOS_TANG_M,
        "sincos_table_entry_baked: m must equal SINCOS_TANG_M"
    );
    let _ = m;
    if idx == 0 {
        // (sin 0, cos 0) = (0, 1) at scale w.
        return (W::ZERO, pow10_w);
    }
    let sin = reconstruct::<W>(&SINCOS_TANG_SIN[idx], w, pow10_w);
    let cos = reconstruct::<W>(&SINCOS_TANG_COS[idx], w, pow10_w);
    (sin, cos)
}

